mapper.select:
select c.*, u.user_no, u.nick_name from ai_c_card_code c left join ai_c_user u on u.user_id = c.used_user_id
and c.package_id = #{packageId} and c.package_name like concat('%', #{packageName}, '%') and c.card_code like concat('%', #{cardCode}, '%') and c.status = #{status}
order by c.card_code_id desc
